    // Create test data with some noise
    let x_data = Array2::from_shape_vec((10, 3), vec![
        1.0, 1.0, 0.5,   // obs 1
        1.0, 2.0, 1.0,   // obs 2
        1.0, 3.0, 1.5,   // obs 3
        1.0, 4.0, 2.0,   // obs 4
        1.0, 5.0, 2.5,   // obs 5
        1.0, 6.0, 3.0,   // obs 6
        1.0, 7.0, 3.5,   // obs 7
        1.0, 8.0, 4.0,   // obs 8
        1.0, 9.0, 4.5,   // obs 9
        1.0, 10.0, 5.0,  // obs 10
    ])?;

    // True model: y = 2 + 1.5*x1 + 0.5*x2 + noise
    let y_data = Array1::from(vec![4.25, 5.5, 7.25, 8.5, 10.75, 11.0, 13.25, 14.5, 16.75, 17.0]);

    // Test Lasso regression
    println!("\n--- Testing Lasso Regression ---");
    let lasso_fit = Lasso::fit(x_data.view(), y_data.view(), 0.1, None)?;
    println!("Lasso coefficients: {:?}", lasso_fit.coefficients());
    println!("Lasso R²: {:.4}", lasso_fit.summary().r_squared);
    println!("Lasso iterations: {}", lasso_fit.iterations);
    println!("Lasso converged: {}", lasso_fit.converged);

    // Test Ridge regression
    println!("\n--- Testing Ridge Regression ---");
    let ridge_fit = Ridge::fit(x_data.view(), y_data.view(), 0.1, None)?;
    println!("Ridge coefficients: {:?}", ridge_fit.coefficients());
    println!("Ridge R²: {:.4}", ridge_fit.summary().r_squared);
    println!("Ridge iterations: {}", ridge_fit.iterations);
    println!("Ridge converged: {}", ridge_fit.converged);

    // Test Bootstrap (smaller sample for speed)
    println!("\n--- Testing Bootstrap ---");
    match lasso_fit.bootstrap(100) {
        Ok(bootstrap_result) => {
            println!("Bootstrap estimates: {:?}", bootstrap_result.estimates);
            println!("Bootstrap std errors: {:?}", bootstrap_result.std_errors);
            println!("Bootstrap completed successfully with {} samples", bootstrap_result.statistics.nrows());
        }
        Err(e) => {
            println!("Bootstrap error: {}", e);
        }
    }

    println!("\n=== Sprint 6 Features Working! ===");
    Ok(())
}

